// Package clients contains Connect client adapters for peer services.
package clients

import (
	"context"
	"net/http"

	"connectrpc.com/connect"

	// Generated by buf generate
	"p9e.in/samavaya/agriculture/pest-prediction-service/internal/ports/outbound"
	sensorv1 "p9e.in/samavaya/agriculture/sensor-service/api/v1"
	sensorv1connect "p9e.in/samavaya/agriculture/sensor-service/api/v1/sensorv1connect"
)

type sensorClient struct {
	client sensorv1connect.SensorServiceClient
}

// NewSensorClient creates a Connect-backed SensorClient.
func NewSensorClient(baseURL string, httpClient *http.Client, opts ...connect.ClientOption) outbound.SensorClient {
	return &sensorClient{
		client: sensorv1connect.NewSensorServiceClient(httpClient, baseURL, opts...),
	}
}

func (c *sensorClient) SensorExists(ctx context.Context, uuid, tenantID string) (bool, error) {
	resp, err := c.client.GetSensor(ctx, connect.NewRequest(&sensorv1.GetSensorRequest{Id: uuid}))
	if err != nil {
		return false, nil
	}
	return resp.Msg.GetSensor() != nil, nil
}

func (c *sensorClient) GetLatestReading(ctx context.Context, sensorUUID, tenantID string) (float64, error) {
	resp, err := c.client.GetLatestReading(ctx, connect.NewRequest(&sensorv1.GetLatestReadingRequest{SensorId: sensorUUID}))
	if err != nil {
		return 0, err
	}
	return resp.Msg.GetValue(), nil
}
